  function calculateLiveDutyTime(user) {
    if (!user.attendance) return 0
    console.log("[DEBUG] User:", user.name, "Attendance:", user.attendance)
    let total = 0
    const today = dayjs().format("YYYY-MM-DD")
    const currentTime = dayjs()

