                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Coming Time</label>
                      <input
                        type="time"
                        value={comingTime}
                        onChange={(e) => setComingTime(e.target.value)}
                        className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#00cec8] focus:border-transparent"
                      />
                      <button
                        type="button"
                        onClick={handleUpdateComing}
                        className="mt-2 w-full px-4 py-2 bg-[#00cec8] text-white rounded-lg hover:bg-[#00b8b3] transition-colors duration-200"
                      >
                        Update Coming Time
                      </button>
                    </div>

                    {comingTime && (
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">Finishing Time</label>
                        <input
                          type="time"
                          value={finishingTime}
                          onChange={(e) => setFinishingTime(e.target.value)}
                          className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-[#00cec8] focus:border-transparent"
                        />
                        <button
                          type="button"
                          onClick={handleUpdateFinishing}
                          className="mt-2 w-full px-4 py-2 bg-[#00cec8] text-white rounded-lg hover:bg-[#00b8b3] transition-colors duration-200"
                        >
                          Update Finishing Time
                        </button>
                      </div>
                    )}
                  </div>

                  {errorMsg && (
                    <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
                      <p className="text-red-800">{errorMsg}</p>
                    </div>
                  )}

                  {successMsg && (
                    <div className="p-4 bg-green-50 border border-green-200 rounded-lg">
                      <p className="text-green-800">{successMsg}</p>
                    </div>
                  )}

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Duty Schedule</label>
                    <Select
                      value={dutySchedule}
                      onChange={(value) => {
                        setDutySchedule(value)
                        if (value === "Early Morning") {
                          setComingTime("04:30")
                          setFinishingTime("07:30")
                        } else if (value === "Morning") {
                          setComingTime("08:00")
                          setFinishingTime("11:00")
                        } else if (value === "Evening") {
                          setComingTime("15:30")
                          setFinishingTime("19:30")
                        } else {
                          setComingTime("")
                          setFinishingTime("")
                        }
                      }}
                      placeholder="Select a schedule"
                      className="w-full"
                      allowClear
                    >
                      <Select.Option value="Early Morning">Early Morning (4:30 AM – 7:30 AM)</Select.Option>
                      <Select.Option value="Morning">Morning (8:00 AM – 11:00 AM)</Select.Option>
                      <Select.Option value="Evening">Evening (3:30 PM – 7:30 PM)</Select.Option>
                    </Select>
                  </div>
                </form>
              </div>
            </div>

            {/* QR Scanner */}
            <div className="mt-8 bg-white rounded-xl shadow-sm border border-gray-200">
              <div className="p-6">
                <button
                  onClick={() => setShowScanner((s) => !s)}
                  className="mb-4 px-4 py-2 bg-[#00cec8] text-white rounded-lg hover:bg-[#00b8b3] transition-colors duration-200"
                >
                  {showScanner ? "Hide" : "Show"} QR Scanner
                </button>
                {showScanner && <QrScannerComponent onScan={handleQrScan} />}
              </div>
            </div>

            {/* Selected User Attendance Records */}
            {attendance && attendance.length > 0 && (
              <div className="mt-8 bg-white rounded-xl shadow-sm border border-gray-200">
                <div className="p-6 border-b border-gray-200">
                  <h3 className="text-lg font-semibold text-gray-900">Selected User Attendance Records</h3>
                </div>
                <div className="p-6">
                  <Table
                    columns={attendanceColumns}
                    dataSource={attendance}
                    rowKey="date"
                    pagination={false}
                    size="middle"
                  />
                </div>
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  )
}

// PrivateRoute for role-based protection
function PrivateRoute({ children, role }) {
  if (!isAuthenticated()) {
    return <Navigate to="/admin" replace />
  }
  if (role && getAdminRole() !== role) {
    return <Navigate to="/admin" replace />
  }
  return children
}

function App() {
  return (
    <ConfigProvider theme={{ token: { colorPrimary: "#00cec8" } }}>
      <Router>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/admin" element={<Login />} />
          <Route
            path="/dashboard/super"
            element={
              <PrivateRoute role="super">
                <SuperAdminDashboard />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/super/add-user"
            element={
              <PrivateRoute role="super">
                <AddUserPage />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/super/view-all-users"
            element={
              <PrivateRoute role="super">
                <ViewAllUsers />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/super/update-duty"
            element={
              <PrivateRoute role="super">
                <SecondaryAdminUpdateDuty />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/super/attendance-history"
            element={
              <PrivateRoute role="super">
                <ViewAllUsers />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/secondary"
            element={
              <PrivateRoute role="secondary">
                <SecondaryAdminDashboard />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/secondary/view-users"
            element={
              <PrivateRoute role="secondary">
                <SecondaryAdminViewUsers />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/secondary/update-duty"
            element={
              <PrivateRoute role="secondary">
                <SecondaryAdminUpdateDuty />
              </PrivateRoute>
            }
          />
          <Route
            path="/dashboard/secondary/attendance-history"
            element={
              <PrivateRoute role="secondary">
                <ViewAllUsers />
              </PrivateRoute>
            }
          />
          <Route path="/user/:userId" element={<UserStatusPage />} />
        </Routes>
      </Router>
    </ConfigProvider>
  )
}

export default App
